// Central Formatting Router (n8n Code Node)
const inputData = $input.first().json;
const rawContent = inputData.content || '';
const isSuccess = rawContent.includes('SUCCESSFUL');
const repo = inputData.repository || 'unknown-repo';
const commit = (inputData.commit || 'unknown').substring(0, 7);

// 1. Discord Embed Structure
const discordPayload = {
  embeds: [{
    title: "n8n GitOps CI/CD",
    description: rawContent,
    color: isSuccess ? 3066993 : 15158332 // Green for success, Red for failure
  }]
};

// 2. Slack Block Kit Structure
const slackPayload = {
  text: isSuccess ? `🚀 *Deploy Success*` : `🚨 *Deploy Blocked*`,
  blocks: [
    {
      type: "section",
      text: {
        type: "mrkdwn",
        text: rawContent
      }
    }
  ]
};

// 3. Telegram HTML Format
const telegramPayload = {
  text: `<b>n8n GitOps Alert</b>\n\n${rawContent.replace(/\*\*/g, '<b>').replace(/\*\*/g, '</b>')}`,
  parse_mode: 'HTML'
};

// 4. Clean HTML Email Body
const emailPayload = {
  subject: `[GitOps] ${isSuccess ? '✅ SUCCESS' : '❌ FAILED'} - ${repo} (${commit})`,
  html: `
    <div style="font-family: Arial, sans-serif; max-width: 600px; padding: 20px; border: 1px solid #ddd; border-radius: 8px;">
      <h2 style="color: ${isSuccess ? '#2ecc71' : '#e74c3c'}">n8n GitOps Pipeline Report</h2>
      <p style="white-space: pre-wrap; font-size: 14px; line-height: 1.5; color: #333;">${rawContent.replace(/\n/g, '<br>')}</p>
      <hr style="border: none; border-top: 1px solid #eee; margin: 20px 0;">
      <small style="color: #777;">Triggered by n8n Pipeline Engine</small>
    </div>
  `
};

return [{ 
  json: {
    discord: discordPayload,
    slack: slackPayload,
    telegram: telegramPayload,
    email: emailPayload
  }
}];

// Generate detailed report for failing test cases
const inputData = $input.first().json;
const errorsFormatted = inputData.test_errors.map(err => `❌ ${err}`).join('\n');

return [{
    json: {
        ...inputData,
        content: `⚠️ **DEPLOYMENT BLOCKER: Integration Tests Failed**\n\n**Repo:** ${inputData.repository}\n**Commit:** \\`${inputData.commit}\\`\n\n**Test Results:**\n${errorsFormatted}\n\nPipeline status: **Aborted. Rollback triggered (Staging container rejected).**`
    }
}];

// Generate detailed report for linter errors
const inputData = $input.first().json;
const errorsFormatted = inputData.errors.map(err => `❌ ${err}`).join('\n');

return [{
    json: {
        ...inputData,
        content: `🚨 **DEPLOYMENT BLOCKER: Linter Errors Found**\n\n**Repo:** ${inputData.repository}\n**Commit:** \\`${inputData.commit}\\`\n\n**Errors:**\n${errorsFormatted}\n\nPipeline status: **Aborted. Fix styling/security standards before pushing.**`
    }
}];

// Generate detailed report for successful deploys
const inputData = $input.first().json;
return [{
    json: {
        ...inputData,
        content: `🚀 **DEPLOYMENT SUCCESSFUL**

**Repo:** ${inputData.repository}
**Commit:** \`${inputData.commit}\`

🟩 **Linter Audit:** Passed (0 errors)
🟩 **Integration Tests:** Passed (0 errors)

Pipeline status: **Active & Running in Production.**`
    }
}];

// 1. Pull Git metadata from the Linter node to keep it alive
const gitMetadata = $('JS Static Linter').item.json;

// 2. Grab the ACTUAL response returned by your "Deploy to Staging" node
const stagingResponse = $input.first().json; 
const errors = [];

// 3. Real deployment health check
if (!stagingResponse) {
    errors.push('[TEST FAILED] Received no response from the Staging API.');
} else if (stagingResponse.error) {
    errors.push(`[TEST FAILED] Staging deployment failed: ${stagingResponse.error.message || stagingResponse.error}`);
} else if (!stagingResponse.id) {
    // If n8n successfully creates/updates a workflow, it returns a JSON object with an "id"
    errors.push('[TEST FAILED] Staging deployment did not return a valid workflow ID.');
}

return [{
    json: {
        ...gitMetadata, // Forwards repository, commit, and workflow_data to the next nodes
        tests_passed: errors.length === 0,
        test_errors: errors,
        workflow_id: stagingResponse?.id || null
    }
}];

// 2. Static Analysis & Linting Code Node
const inputData = $input.first().json;
const workflow = inputData.workflow_data;
const errors = [];

if (!workflow || !workflow.nodes) {
    errors.push('Invalid workflow format: missing nodes array.');
} else {
    workflow.nodes.forEach(node => {
        // Rule 1: No hardcoded API keys/secrets in parameters (Simple regex)
        const nodeStr = JSON.stringify(node);
        const secretPatterns = [/api_key/i, /secret/i, /password/i, /"key":\s*"[a-zA-Z0-9]{10,}"/i];

        secretPatterns.forEach(pattern => {
            if (pattern.test(nodeStr)) {
                errors.push(`[SECURITY CRITICAL] Node "${node.name}" seems to contain hardcoded secrets! Use n8n Credentials instead.`);
            }
        });

        // Rule 2: Forbidden nodes check
        const forbiddenTypes = ['n8n-nodes-base.executeCommand', 'n8n-nodes-base.ssh'];
        if (forbiddenTypes.includes(node.type)) {
            errors.push(`[POLICY VIOLATION] Node "${node.name}" uses a forbidden node type (${node.type}).`);
        }

        // Rule 3: Node naming standards
        if (node.name.startsWith('Code') || node.name.startsWith('HTTP Request')) {
            errors.push(`[STYLE WARNING] Node "${node.name}" is using default naming. Please rename for readability.`);
        }
    });
}

return [{
    json: {
        ...inputData,
        linter_passed: errors.length === 0,
        errors: errors
    }
}];

// 1. Verify GitHub Signature (HMAC-SHA256)
const headers = $input.item.json.headers || {};
const body = $input.item.json.body || {};
const signature = headers['x-hub-signature-256'];

// Mock verification for testing inside n8n without actual GitHub webhook
const isValid = signature ? true : true; 

return [{
    json: {
        verified: isValid,
        payload: body,
        repository: body.repository?.full_name || 'demo-repo/n8n-workflows',
        commit: body.head_commit?.id || 'mock-commit-sha-12345',
        workflow_data: body.workflow_json || {
            'nodes': [
                { 'name': 'Prod HTTP Node', 'type': 'n8n-nodes-base.httpRequest', 'parameters': { 'url': 'https://api.test.com' } },
                { 'name': 'Insecure Node', 'type': 'n8n-nodes-base.code', 'parameters': { 'jsCode': "const secret = '12345-SUPER-SECRET';" } }
            ]
        }
    }
}];

