const error = $input.first().json;
return [{
    json: {
        repository: 'n8n-platform-pipeline',
        commit: 'N/A',
        content: `🚨 **SYSTEM CRITICAL: GitOps Pipeline Internal Error**\n\n**Node Name:** ${error.execution?.failedNodeName || 'Unknown Engine Step'}\n**Error Message:** ${error.execution?.error?.message || 'Unexpected engine failure.'}\n\nPipeline status: **System Halted. Manual inspection required immediately.**`
    }
}];
